SELECT COUNT(*) AS passed_bills_count
FROM states_bills_bridge
WHERE bill_status = 'passed' AND state_id = 1;

SELECT bill_number
FROM bills
WHERE bill_id = 0;

SELECT voting_center_name
FROM voting_centers
WHERE location = 'Alabama';

SELECT member_name
FROM committee_members
WHERE committee_id = (SELECT committee_id FROM committees WHERE committee_name = 'Committee on Health');

SELECT COUNT(bill_id) AS bill_count
FROM bills
WHERE state_id = 1;

SELECT topic_name
FROM bill_topics
WHERE topic_id = 0;

SELECT bill_number 
FROM bills 
WHERE introduction_date = (SELECT MAX(introduction_date) FROM bills);
